# %%
# Step 1.1 Clean the mount point and re-mount Google Drive in Colab
# This error happens when /content/drive already has local files from a previous session.
# We safely unmount (if mounted), remove the stale folder, recreate it, then mount and reinitialize paths/logs.

from google.colab import drive
from pathlib import Path
import os, shutil, datetime

MOUNT_POINT = "/content/drive"

# 1) Unmount if currently mounted (ignore errors)
try:
    drive.flush_and_unmount()
except Exception:
    pass

# 2) If the mountpoint exists locally (not mounted), remove it so mount can proceed
if os.path.exists(MOUNT_POINT) and not os.path.ismount(MOUNT_POINT):
    shutil.rmtree(MOUNT_POINT)
os.makedirs(MOUNT_POINT, exist_ok=True)

# 3) Mount fresh
drive.mount(MOUNT_POINT, force_remount=True)

# 4) Recreate project paths + a minimal session log
PROJECT_ROOT = Path("/content/drive/MyDrive/epigen_project").resolve()
(PROJECT_ROOT / "logs").mkdir(parents=True, exist_ok=True)

with open(PROJECT_ROOT / "logs" / "session_init.txt", "a") as f:
    f.write(f"[{datetime.datetime.utcnow().isoformat()}Z] Re-initialized project at {PROJECT_ROOT}\n")

print(f"Project root: {PROJECT_ROOT}")

