# %%
# 1.3 Runtime checks
import sys, shutil, platform, subprocess, json

def check_gpu():
    try:
        # Try PyTorch CUDA check (works if torch is preinstalled)
        import torch
        if torch.cuda.is_available():
            name = torch.cuda.get_device_name(0)
            return {"available": True, "backend": "torch", "device_name": name}
    except Exception:
        pass
    # Fallback to nvidia-smi
    try:
        out = subprocess.check_output(["nvidia-smi", "--query-gpu=name,memory.total", "--format=csv,noheader"], text=True)
        name, mem = [x.strip() for x in out.splitlines()[0].split(",")]
        return {"available": True, "backend": "nvidia-smi", "device_name": name, "memory_total": mem}
    except Exception:
        return {"available": False}

def bytes_to_gb(b): return round(b / (1024**3), 2)

# Python & platform
py = sys.version.split()[0]
plat = platform.platform()

# RAM (Colab has psutil preinstalled; if not, we fallback to /proc/meminfo)
try:
    import psutil
    vm = psutil.virtual_memory()
    ram_total_gb = bytes_to_gb(vm.total)
    ram_free_gb = bytes_to_gb(vm.available)
except Exception:
    import re
    with open("/proc/meminfo") as fh:
        mem_kb = int(re.search(r"MemTotal:\s+(\d+) kB", fh.read()).group(1))
    ram_total_gb = round(mem_kb / (1024**2), 2)
    ram_free_gb = None

# Disk usage for /content and project root
disk_content = shutil.disk_usage("/content")
disk_drive   = shutil.disk_usage(str(PROJECT_ROOT))

report = {
    "python_version": py,
    "platform": plat,
    "gpu": check_gpu(),
    "ram_total_GB": ram_total_gb,
    "ram_free_GB": ram_free_gb,
    "disk_/content_total_GB": bytes_to_gb(disk_content.total),
    "disk_/content_free_GB": bytes_to_gb(disk_content.free),
    "disk_project_total_GB": bytes_to_gb(disk_drive.total),
    "disk_project_free_GB": bytes_to_gb(disk_drive.free),
    "notes": {
        "colab_quota": "GPU/TPU quotas reset periodically; avoid long idle sessions. Persist outputs to Drive.",
        "recommendation": "Aim for ≥26–52 GB RAM runtime for deep models; shard large downloads and cache intermediates."
    }
}

# Save and print
with open(PROJECT_ROOT / "logs" / "runtime_check.json", "w") as f:
    json.dump(report, f, indent=2)

print(json.dumps(report, indent=2))

