# %%
# Step 3.6A: Log hash and size for baselineLD_v2.2.tgz

import hashlib
from pathlib import Path
import os
from pathlib import Path

# Define and export PROJECT_ROOT (adjust to your actual working path if needed)
os.environ["PROJECT_ROOT"] = "/content/drive/MyDrive/epigen_project"

# Define input and output paths
ref_dir = Path(os.environ["REF_DIR"])
archive = ref_dir / "baselineLD_v2.2.tgz"
log_file = Path(os.environ["PROJECT_ROOT"]) / "logs" / "ref_hashes.txt"
log_file.parent.mkdir(parents=True, exist_ok=True)

# Function to compute hashes
def compute_hashes(filepath):
    sha256 = hashlib.sha256()
    md5 = hashlib.md5()
    with filepath.open("rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
            md5.update(chunk)
    return sha256.hexdigest(), md5.hexdigest(), filepath.stat().st_size

# Compute and write hashes
sha256_hash, md5_hash, file_size = compute_hashes(archive)

with log_file.open("a") as f:
    f.write(f"\n# baselineLD_v2.2.tgz\n")
    f.write(f"File: {archive.resolve()}\n")
    f.write(f"Size: {file_size} bytes\n")
    f.write(f"SHA256: {sha256_hash}\n")
    f.write(f"MD5: {md5_hash}\n")

print(f"Logged hash and size info for: {archive.name}")

# %%
# Step 3.6B – Recursively log SHA256 hashes, sizes, and line counts for REF_DIR contents

import hashlib
from pathlib import Path
import os

ref_dir = Path(os.environ["REF_DIR"])
log_file = Path(os.environ["PROJECT_ROOT"]) / "logs" / "ref_hashes.txt"
log_file.parent.mkdir(parents=True, exist_ok=True)

def hash_file_sha256(file_path):
    hasher = hashlib.sha256()
    with open(file_path, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            hasher.update(chunk)
    return hasher.hexdigest()

with open(log_file, "a") as f:
    f.write(f"\n# Recursive SHA256 hash log for ref_dir ({ref_dir})\n")
    for path in sorted(ref_dir.rglob("*")):
        if path.is_file():
            rel_path = path.relative_to(ref_dir)
            sha256 = hash_file_sha256(path)
            size = path.stat().st_size
            try:
                line_count = sum(1 for _ in open(path)) if path.suffix in [".txt", ".gz", ".snplist"] else "N/A"
            except Exception:
                line_count = "N/A"
            f.write(f"{rel_path}\n  sha256: {sha256}\n  size_bytes: {size}\n  lines: {line_count}\n")

print(f"Logged hashes for all files in: {ref_dir}")
print(f"Log file updated: {log_file}")

