# %%
## Step 4.2F – Manual conversion from VCF to TSV format using Python
# For each VCF file, extract: rsID, effect_allele, other_allele, beta (ES), SE, pval (from LP), EAF (AF), N (SS)
# Output: Clean .tsv file per trait, stored in sumstats/ folder

import gzip
import pandas as pd
from pathlib import Path
import numpy as np

def vcf_to_tsv(vcf_path, output_path):
    records = []
    with gzip.open(vcf_path, "rt") as f:
        for line in f:
            if line.startswith("#CHROM"):
                header = line.strip().split("\t")
                continue
            if line.startswith("#"):
                continue

            parts = line.strip().split("\t")
            chrom, pos, rsid, ref, alt, qual, filt, info, fmt, sample = parts[:10]

            fmt_fields = fmt.split(":")
            sample_fields = sample.split(":")
            fmt_dict = dict(zip(fmt_fields, sample_fields))

            try:
                beta = float(fmt_dict.get("ES", "nan"))
                se = float(fmt_dict.get("SE", "nan"))
                logp = float(fmt_dict.get("LP", "nan"))
                pval = 10 ** (-logp) if not np.isnan(logp) else np.nan
                eaf = float(fmt_dict.get("AF", "nan"))
                n = float(fmt_dict.get("SS", "nan"))

                records.append({
                    "rsID": rsid,
                    "effect_allele": alt,
                    "other_allele": ref,
                    "beta": beta,
                    "se": se,
                    "pval": pval,
                    "eaf": eaf,
                    "N": n
                })
            except Exception as e:
                continue  # skip malformed rows

    df = pd.DataFrame(records)
    df.to_csv(output_path, sep="\t", index=False)
    print(f"Converted and saved: {output_path.name} ({len(df)} variants)")

# Define paths
sumstats_dir = Path("/content/drive/MyDrive/epigen_project/sumstats")

vcf_files = {
    "ukb-b-10215.vcf.gz": "ukb-b-10215.tsv",
    "ukb-b-7478.vcf.gz": "ukb-b-7478.tsv"
}

for vcf_file, out_file in vcf_files.items():
    vcf_path = sumstats_dir / vcf_file
    out_path = sumstats_dir / out_file
    if not out_path.exists():
        vcf_to_tsv(vcf_path, out_path)
    else:
        print(f"Skipping {out_file}, already exists.")

