        # Check numeric validity
        for col in ["beta", "se", "pval", "eaf", "N"]:
            if col in df.columns:
                invalid = df[col].isna().sum()
                non_numeric = df[col].apply(lambda x: not str(x).replace('.', '', 1).isdigit()).sum()
