# %%
# Step 4.4 – QC Snapshot on Cleaned Summary Statistics
# This step computes basic QC metrics for each cleaned file: total variant count, allele sanity (A/C/G/T only),
# and non-missing counts for beta, se, pval, eaf, and N. It flags unexpected alleles or malformed data.

import pandas as pd
from pathlib import Path

# Set project root explicitly
project_root = Path("/content/drive/MyDrive/epigen_project")
sumstats_dir = project_root / "sumstats"

# List of cleaned summary statistics files
cleaned_files = [
    "ukb-b-10215_cleaned.tsv",
    "ukb-b-7478_cleaned.tsv",
    "GCST90000025_harmonized_cleaned.tsv"
]

# Acceptable allele values for sanity check
valid_alleles = {"A", "C", "G", "T"}

# QC summary collector
qc_summary = []

for fname in cleaned_files:
    fpath = sumstats_dir / fname
    try:
        df = pd.read_csv(fpath, sep="\t", dtype=str)

        print(f"\nInspecting QC for: {fname}")
        print("-" * 60)

        total = len(df)
        beta_missing = df["beta"].isna().sum()
        se_missing = df["se"].isna().sum()
        pval_missing = df["pval"].isna().sum()
        eaf_missing = df["eaf"].isna().sum()
        N_missing = df["N"].isna().sum()

        # Allele sanity checks (uppercase and strip whitespace)
        effect_allele_valid = df["effect_allele"].str.upper().isin(valid_alleles)
        other_allele_valid = df["other_allele"].str.upper().isin(valid_alleles)
        allele_sane_count = (effect_allele_valid & other_allele_valid).sum()
        allele_flagged = total - allele_sane_count

        # Display summary
        print(f"Total variants         : {total:,}")
        print(f"Missing in beta        : {beta_missing:,}")
        print(f"Missing in se          : {se_missing:,}")
        print(f"Missing in pval        : {pval_missing:,}")
        print(f"Missing in eaf         : {eaf_missing:,}")
        print(f"Missing in N           : {N_missing:,}")
        print(f"Variants with A/C/G/T  : {allele_sane_count:,}")
        print(f"Variants with invalid alleles : {allele_flagged:,}")

        # Store summary
        qc_summary.append({
            "file": fname,
            "total_variants": total,
            "missing_beta": beta_missing,
            "missing_se": se_missing,
            "missing_pval": pval_missing,
            "missing_eaf": eaf_missing,
            "missing_N": N_missing,
            "allele_invalid": allele_flagged
        })

    except Exception as e:
        print(f"Error processing {fname}: {e}")

# Optional: Save QC summary to file
qc_df = pd.DataFrame(qc_summary)
qc_df.to_csv(project_root / "logs" / "qc_summary.tsv", sep="\t", index=False)
print("\nQC summary saved to logs/qc_summary.tsv")

