COMB = os.path.join(REF, "combined", TRACK)
WLD  = os.path.join(REF, "weights_hm3_no_hla")

def rgz(p):
    return pd.read_csv(p, sep="\t", compression="gzip", low_memory=False)

bad = {}  # name -> list of (chr, sd)

for chr_ in range(1,23):
    l2p  = os.path.join(COMB, f"baselineLD_plus_{TRACK}.{chr_}.l2.ldscore.gz")
    wldp = os.path.join(WLD,  f"weights.hm3_no_hla.{chr_}.l2.ldscore.gz")
    if not (os.path.exists(l2p) and os.path.exists(wldp)):
        print(f"[skip] chr{chr_} (missing l2/wld)");
        continue

    l2  = rgz(l2p);  l2.columns  = [c.upper() for c in l2.columns]
    wld = rgz(wldp); wld.columns = [c.upper() for c in wld.columns]

    # HM3 regression SNP set
    hm3_snps = set(wld["SNP"].astype(str))
    l2 = l2[l2["SNP"].astype(str).isin(hm3_snps)].reset_index(drop=True)

