project_root <- "/content/drive/MyDrive/epigen_project"
ref_dir      <- file.path(project_root, "ldsc_ref")
out_dir      <- file.path(project_root, "logs", "partitioned", "results")
dir.create(out_dir, recursive = TRUE, showWarnings = FALSE)

ld_prefix  <- file.path(ref_dir, "combined", "E091", "baselineLD_plus_E091.")
wld_prefix <- file.path(ref_dir, "weights_hm3_no_hla", "weights.hm3_no_hla.")
