import os, re, csv, sys
from pathlib import Path

root = Path("/content/drive/MyDrive/epigen_project")
if not root.exists():
    print(f"[scan] root not found: {root}", file=sys.stderr)
    sys.exit(1)

print(f"[scan] root: {root}")

# Collect all bim/bed/fam
bims, beds, fams = [], [], []
for dirpath, dirnames, filenames in os.walk(root):
    for fn in filenames:
        f = Path(dirpath)/fn
        low = fn.lower()
        if low.endswith(".bim"): bims.append(f)
        elif low.endswith(".bed"): beds.append(f)
        elif low.endswith(".fam"): fams.append(f)

print(f"[scan] found: {len(bims)} .bim, {len(beds)} .bed, {len(fams)} .fam")

# Group files that look like 1000G.EUR.QC.<chr>[.ext] (also accepts 'chr<chr>')
qc_pat = re.compile(r"^(1000G\.EUR\.QC\.(?:chr)?([0-9XY]+))\.(bim|bed|fam)$", re.IGNORECASE)

groups = {}  # key: (dir, baseprefix) -> dict(ext->path), chr
def add_to_group(path):
    m = qc_pat.match(path.name)
    if not m:
        return False
    baseprefix, chrom, ext = m.group(1), m.group(2), m.group(3).lower()
    key = (str(path.parent), baseprefix)
    d = groups.setdefault(key, {"CHR": chrom, "bim": None, "bed": None, "fam": None})
    d[ext] = str(path)
    return True

non_qc_bims = []
for p in bims:
    if not add_to_group(p):
        non_qc_bims.append(str(p))

# Also try to attach corresponding bed/fam to existing groups in same dir
for coll, ext in ((beds,"bed"), (fams,"fam")):
    for p in coll:
        m = qc_pat.match(p.name)
        if m:
            baseprefix = m.group(1)
            key = (str(p.parent), baseprefix)
            if key in groups:
                groups[key][ext] = str(p)

# Summaries
rows = []
have_chr = set()
for (d, base), info in sorted(groups.items(), key=lambda x: (x[0][0], x[0][1])):
    chrom = info["CHR"]
    exts_present = [e for e in ("bim","bed","fam") if info[e]]
    status = "complete" if len(exts_present)==3 else ("partial" if len(exts_present)>0 else "empty")
    rows.append({
        "dir": d,
        "baseprefix": base,
        "CHR": chrom,
        "bim": "yes" if info["bim"] else "no",
        "bed": "yes" if info["bed"] else "no",
        "fam": "yes" if info["fam"] else "no",
        "status": status,
    })
    if info["bim"]:
        # record numeric autosomes; keep X as-is
        if chrom.isdigit():
            have_chr.add(int(chrom))
        else:
            have_chr.add(chrom.upper())

print(f"[qc-style groups] {len(rows)} groups")
# Print a small preview
for r in rows[:12]:
    print(f"- chr{r['CHR']:>2}  {r['status']:<8}  {r['dir']}/{r['baseprefix']}.[bim|bed|fam]")

# Chromosome coverage 1..22
missing = [c for c in range(1,23) if c not in have_chr]
present = [c for c in range(1,23) if c in have_chr]
print(f"[coverage] autosomes present: {present}")
print(f"[coverage] autosomes MISSING: {missing if missing else 'none'}")
if "X" in have_chr or 23 in have_chr:
    print("[coverage] X present")

# Write a CSV manifest for reference
out_csv = root/"fine_map"/"jobs"/"ldref_scan_manifest.csv"
out_csv.parent.mkdir(parents=True, exist_ok=True)
with out_csv.open("w", newline="") as f:
    w = csv.DictWriter(f, fieldnames=["dir","baseprefix","CHR","bim","bed","fam","status"])
    w.writeheader(); w.writerows(rows)
print(f"[scan] wrote: {out_csv}")

# Non-QC BIMs (if any)
if non_qc_bims:
    print(f"[note] {len(non_qc_bims)} BIM(s) not matching '1000G.EUR.QC.<chr>.bim' pattern. First few:")
    for p in non_qc_bims[:10]:
        print("  -", p)

