from pathlib import Path
import pandas as pd

plink_dir = Path("/content/drive/MyDrive/epigen_project/ldsc_ref/1000G_EUR_Phase3_plink")

def choose_trio(d, chrom):
    c = int(str(chrom).lower().replace("chr",""))
    # try non-padded, then padded
    for base in [f"1000G.EUR.QC.{c}", f"1000G.EUR.QC.{c:02d}"]:
        trio = [d/f"{base}.bim", d/f"{base}.bed", d/f"{base}.fam"]
        if all(p.exists() for p in trio):
            return trio
    # fallback: glob and match numeric suffix
    for p in d.glob("1000G.EUR.QC.*.bim"):
        try:
            if int(p.stem.split(".")[-1]) == c:
                base = p.stem
                trio = [d/f"{base}.bim", d/f"{base}.bed", d/f"{base}.fam"]
                if all(q.exists() for q in trio):
                    return trio
        except Exception:
            pass
    return None

for c in [1, 10, 20]:
    trio = choose_trio(plink_dir, c)
    if trio is None:
        print(f"[FAIL] chr{c}: BIM/BED/FAM trio not found under {plink_dir}")
        continue
    bim, bed, fam = trio
    try:
        df = pd.read_csv(bim, sep=r"\s+", header=None,
                         names=["CHR","SNP","CM","BP","A1","A2"], dtype={1:str})
        print(f"[OK] chr{c}: using {bim.name} (rows={len(df)}); bed={bed.exists()} fam={fam.exists()}")
        print(df.head(3).to_string(index=False))
    except Exception as e:
        print(f"[ERROR] chr{c}: failed reading {bim.name}: {e}")
