import os, csv, shlex, sys
from pathlib import Path

root = Path("/content/drive/MyDrive/epigen_project")
manifest = root/"fine_map"/"jobs"/"susie_jobs_pm250kb_manifest.csv"
runner   = root/"fine_map"/"jobs"/"run_susie_one.py"
fix_path = root/"fine_map"/"jobs"/"susie_fix_missing_2.sh"

missing = {"ALM_chr12_8828383","ALM_chr12_9113002"}

if not manifest.exists():
    raise SystemExit(f"[ERR] Missing manifest: {manifest}")
if not runner.exists():
    raise SystemExit(f"[ERR] Missing runner: {runner}")

rows = list(csv.DictReader(manifest.open()))
