import gzip, re, sys
from pathlib import Path
import numpy as np, pandas as pd

root = Path("/content/drive/MyDrive/epigen_project")
sumstats_path = root/"sumstats"/"GCST90000025.formatted.txt.gz"  # ALM sumstats
plink_dir = root/"ldsc_ref"/"1000G_EUR_Phase3_plink"
targets = [
    ("ALM", "ALM_chr12_8828383"),
    ("ALM", "ALM_chr12_9113002"),
]

def read_snplist(p):
    with open(p, "r") as f:
        return [ln.strip().split()[0] for ln in f if ln.strip()]

def read_ld(path):
    with gzip.open(path, "rt") as f:
        arr = np.loadtxt(f)
    if np.isscalar(arr):
        arr = np.array([[float(arr)]], dtype=float)
    return np.asarray(arr, dtype=float)

def guess_snp_col(df):
    for cands in [["SNP","rsid","RSID","MarkerName","variant_id"], ["ID","variant","rsID"]]:
        for c in cands:
            if c in df.columns: return c
    return None

def allele_complement(a):
    comp = {"A":"T","T":"A","C":"G","G":"C"}
    return comp.get(a)

def read_bim_for_chr(plink_root, chrom):
    c = int(str(chrom).lower().replace("chr",""))
    d = Path(plink_root)
    cand = d/f"1000G.EUR.QC.{c}.bim"
    if not cand.exists():
        cand = d/f"1000G.EUR.QC.{c:02d}.bim"
    if not cand.exists():
        # last resort: glob and match numeric suffix
        hits = list(d.glob("1000G.EUR.QC.*.bim"))
        got = None
        for h in hits:
            m = re.search(r"\.(\d+)\.bim$", h.name)
            if m and int(m.group(1)) == c:
                got = h; break
        cand = got
    if cand is None or not cand.exists():
        raise FileNotFoundError(f"No BIM for chr {chrom} under {plink_root}")
    cols = ["CHR","SNP","CM","BP","A1","A2"]
    return pd.read_csv(cand, sep=r"\s+", header=None, names=cols, dtype={1:str})

# Load sumstats lightly
SS = pd.read_csv(sumstats_path, sep="\t", compression="infer", dtype=str)
snpcol = guess_snp_col(SS)
if snpcol is None:
    print(f"[ERR] Could not detect SNP column in {sumstats_path}", file=sys.stderr)
    sys.exit(1)
SS[snpcol] = SS[snpcol].astype(str).str.replace(r"^rs","rs", regex=True)
hasZ = ("Z" in SS.columns) and SS["Z"].notna().any()
hasBETA_SE = ("BETA" in SS.columns) and ("SE" in SS.columns)

print(f"[sumstats] path={sumstats_path}")
print(f"[sumstats] rows={len(SS)} snpcol={snpcol} hasZ={hasZ} hasBETA+SE={hasBETA_SE}")
print(f"[sumstats] head {snpcol}:")
print(SS[snpcol].head(5).to_string(index=False))

for trait, sentinel in targets:
    m = re.search(r"chr(\d+)_", sentinel, re.IGNORECASE)
    chrnum = m.group(1) if m else None
    outdir = root/"fine_map"/"susie"/"pm250kb"/trait/sentinel
    lddir  = root/"fine_map"/"ld_mats"/"pm250kb"/trait/sentinel
    ld_r   = lddir/"ld.ld.gz"
    ld_snps= lddir/"ld.snplist"

    print("\n"+"="*80)
    print(f"[locus] {trait} {sentinel} (chr{chrnum})")
    print(f"[paths] outdir={outdir}")
    print(f"[paths] ld_r={ld_r.exists()} size={ld_r.stat().st_size if ld_r.exists() else 0}")
    print(f"[paths] ld_snps={ld_snps.exists()} size={ld_snps.stat().st_size if ld_snps.exists() else 0}")

    if not ld_snps.exists():
        print("[diagnose] ld.snplist missing -> cannot proceed here."); continue

    snplist = read_snplist(ld_snps)
    print(f"[diagnose] #ld.snplist={len(snplist)} (first 5) {snplist[:5]}")

    # Sumstats overlap
    SS_sub = SS[SS[snpcol].isin(set(snplist))].copy()
    print(f"[diagnose] in-sumstats overlap with ld.snplist: {len(SS_sub)}")

    # If zero, show hints
    if len(SS_sub) == 0:
        # Show whether sumstats has many rs-style IDs at all
        rs_fraction = (SS[snpcol].str.startswith("rs", na=False)).mean()
        print(f"[hint] sumstats rsID fraction ~ {rs_fraction:.3f} (0..1)")
        print(f"[hint] example sumstats IDs: {SS[snpcol].dropna().astype(str).head(10).tolist()}")
        # Show whether ld.snplist looks like rsIDs
        is_rs = [s.startswith("rs") for s in snplist]
        print(f"[hint] ld.snplist rsID fraction ~ {np.mean(is_rs) if is_rs else 0:.3f}")
        # Try positional mapping idea preview (count how many snplist rsIDs appear in BIM)
        try:
            bim = read_bim_for_chr(plink_dir, chrnum)
            in_bim = bim[bim["SNP"].isin(snplist)]
            print(f"[diagnose] ld.snplist ∩ BIM: {len(in_bim)} / {len(snplist)}")
        except Exception as e:
            print(f"[warn] BIM read failed: {e}")
        continue

    # Allele alignment diagnostics like in runner
    # Read BIM for the chromosome and join
    bim = read_bim_for_chr(plink_dir, chrnum)
    bim = bim[bim["SNP"].isin(snplist)].copy().rename(columns={"A1":"A1_bim","A2":"A2_bim"})

    df = SS_sub.merge(bim[["SNP","A1_bim","A2_bim"]], left_on=snpcol, right_on="SNP", how="inner")
    print(f"[diagnose] after merging with BIM by SNP: {len(df)}")

    # Determine Z vector availability
    z_series = None
    if "Z" in df.columns and df["Z"].notna().any():
        z_series = pd.to_numeric(df["Z"], errors="coerce")
    elif "BETA" in df.columns and "SE" in df.columns:
        z_series = pd.to_numeric(df["BETA"], errors="coerce") / pd.to_numeric(df["SE"], errors="coerce")
    n_non_na_z = int(np.isfinite(z_series).sum()) if z_series is not None else 0
    print(f"[diagnose] z non-NA count before allele filters: {n_non_na_z}")

    a1col = next((c for c in ["A1","EA","EFFECT_ALLELE","ALT","effect_allele"] if c in df.columns), None)
    a2col = next((c for c in ["A2","NEA","OTHER_ALLELE","REF","non_effect_allele"] if c in df.columns), None)

    if a1col and a2col:
        a1 = df[a1col].str.upper()
        a2 = df[a2col].str.upper()
        b1 = df["A1_bim"].str.upper()
        b2 = df["A2_bim"].str.upper()
        comp_a1 = a1.map(allele_complement)
        comp_a2 = a2.map(allele_complement)
        same = (a1==b1) & (a2==b2)
        flip = (a1==b2) & (a2==b1)
        strand_same = (comp_a1==b1) & (comp_a2==b2)
        strand_flip = (comp_a1==b2) & (comp_a2==b1)
        final_same = same | strand_same
        final_flip = flip | strand_flip
        ambig = ~(final_same | final_flip)
        print(f"[diagnose] allele flags: same={int(final_same.sum())} flip={int(final_flip.sum())} ambig={int(ambig.sum())}")

        kept_idx = np.where(~ambig.values)[0]
        print(f"[diagnose] keep after removing ambiguous: {len(kept_idx)}")
    else:
        print(f"[diagnose] sumstats allele cols missing (a1col={a1col}, a2col={a2col}); no allele-based pruning performed.")

    # Show a few IDs for context
    ex = df[snpcol].head(8).tolist() if len(df) else []
    print(f"[examples] merged SNP IDs (up to 8): {ex}")

print("\n[done] diagnostic complete.")
