import os, re, gzip, shlex, subprocess
from pathlib import Path
import numpy as np, pandas as pd

root = Path(os.environ["ROOT"])
sumstats_path = Path(os.environ["SUMSTATS"])
plink_dir = Path(os.environ["PLINK_DIR"])
runner = Path(os.environ["RUNNER"])
N_VAL = int(os.environ["N_VAL"])

targets = [
    ("ALM", "ALM_chr12_8828383"),
    ("ALM", "ALM_chr12_9113002"),
]

def read_snplist(p):
    with open(p, "r") as f:
        return [ln.strip().split()[0] for ln in f if ln.strip()]

def read_bim_for_chr(plink_root, chrom):
    d = Path(plink_root)
    c = int(str(chrom).lower().replace("chr",""))
    cand = d/f"1000G.EUR.QC.{c}.bim"
    if not cand.exists():
        cand = d/f"1000G.EUR.QC.{c:02d}.bim"
    if not cand.exists():
        got = None
        for h in d.glob("1000G.EUR.QC.*.bim"):
            m = re.search(r"\.(\d+)\.bim$", h.name)
            if m and int(m.group(1)) == c:
                got = h; break
        cand = got
    if cand is None or not cand.exists():
        raise FileNotFoundError(f"No BIM for chr {chrom}")
    cols = ["CHR","SNP_bim","CM","BP","A1_bim","A2_bim"]  # rename at read time
    return pd.read_csv(cand, sep=r"\s+", header=None, names=cols, dtype={1:str})

# Load sumstats
SS = pd.read_csv(sumstats_path, sep="\t", compression="infer", dtype=str)
SS.columns = [c.strip() for c in SS.columns]

def pick(df, cands):
    for c in cands:
        if c in df.columns: return c
    return None

snpcol = pick(SS, ["SNP","rsid","RSID","MarkerName","variant_id","ID","variant","rsID"])
chrcol = pick(SS, ["CHR","chrom","chr","#CHR"])
bpcol  = pick(SS, ["BP","pos","POS"])
a1col  = pick(SS, ["A1","EA","EFFECT_ALLELE","ALT","effect_allele"])
a2col  = pick(SS, ["A2","NEA","OTHER_ALLELE","REF","non_effect_allele"])

if snpcol is None or chrcol is None or bpcol is None:
    raise SystemExit(f"[ERR] Need SNP/CHR/BP in sumstats; found SNP={snpcol}, CHR={chrcol}, BP={bpcol}")

SS = SS.copy()
SS[snpcol] = SS[snpcol].astype(str)
SS[chrcol] = SS[chrcol].astype(str).str.replace("^chr","", regex=True)
SS[bpcol]  = pd.to_numeric(SS[bpcol], errors="coerce")

for trait, sentinel in targets:
    m = re.search(r"chr(\d+)_", sentinel, re.IGNORECASE)
    if not m:
        print(f"[{sentinel}] cannot parse chr"); continue
    chrnum = m.group(1)

    lddir  = root/"fine_map"/"ld_mats"/"pm250kb"/trait/sentinel
    outdir = root/"fine_map"/"susie"/"pm250kb"/trait/sentinel
    ld_r   = lddir/"ld.ld.gz"
    ld_snps= lddir/"ld.snplist"

    if not ld_r.exists() or not ld_snps.exists():
        print(f"[{sentinel}] missing LD inputs"); continue

    snps = read_snplist(ld_snps)
    BIM = read_bim_for_chr(plink_dir, chrnum)

    BIM_sub = BIM[BIM["SNP_bim"].isin(snps)].copy()
    if BIM_sub.empty:
        print(f"[{sentinel}] BIM has no overlap with ld.snplist (unexpected)"); continue

    BIM_sub["CHR"] = BIM_sub["CHR"].astype(str)
    BIM_sub["BP"]  = pd.to_numeric(BIM_sub["BP"], errors="coerce")

    # restrict sumstats to this chr and positions seen in BIM_sub
    SS_sub = SS.loc[(SS[chrcol]==str(chrnum)) & (SS[bpcol].isin(set(BIM_sub["BP"]))), :].copy()
    if SS_sub.empty:
        print(f"[{sentinel}] sumstats have no rows at these positions"); continue

    if a1col:
        SS_sub.loc[:, a1col] = SS_sub[a1col].str.upper()
    if a2col:
        SS_sub.loc[:, a2col] = SS_sub[a2col].str.upper()

    # Strict merge (CHR,BP,A1,A2) if possible; else BP-only
    merged = None
    if a1col and a2col:
        merged = SS_sub.merge(
            BIM_sub[["BP","SNP_bim","A1_bim","A2_bim"]],
            left_on=[bpcol, a1col, a2col],
            right_on=["BP","A1_bim","A2_bim"],
            how="inner"
        )
    if merged is None or merged.empty:
        merged = SS_sub.merge(
            BIM_sub[["BP","SNP_bim"]],
            left_on=[bpcol],
            right_on=["BP"],
            how="inner"
        )

    if merged.empty:
        print(f"[{sentinel}] merge by position failed (0 matches)"); continue

    # Replace sumstats SNP column with BIM IDs (SNP_bim), then keep only those in ld.snplist
    fixed = merged.copy()
    fixed.loc[:, snpcol] = fixed["SNP_bim"]
    fixed = fixed.loc[fixed[snpcol].isin(set(snps)), :].copy()
    if fixed.empty:
        print(f"[{sentinel}] after restricting to ld.snplist, 0 variants remain"); continue

    # Keep original SS columns where available (preserve Z or BETA/SE/etc.)
    keep_cols = [c for c in SS.columns if c in fixed.columns]
    fixed = fixed.loc[:, keep_cols].copy()

    outdir.mkdir(parents=True, exist_ok=True)
    tmp_sumstats = outdir/"sumstats.tmp.for_ss.tsv.gz"
    fixed.to_csv(tmp_sumstats, sep="\t", index=False, compression="gzip")
    print(f"[{sentinel}] wrote tmp sumstats: {tmp_sumstats} (rows={len(fixed)})")

    # Run the locus with explicit N
    cmd = [
        "python3", str(runner),
        "--trait", trait,
        "--sentinel", sentinel,
        "--sumstats", str(tmp_sumstats),
        "--ld_r", str(ld_r),
        "--ld_snps", str(ld_snps),
        "--plink_dir", str(plink_dir),
        "--n", str(N_VAL),
        "--L", "10",
        "--coverage", "0.95",
        "--outdir", str(outdir),
    ]
    print("[run]", " ".join(shlex.quote(x) for x in cmd), flush=True)
    rc = subprocess.call(cmd)
    if rc != 0:
        print(f"[{sentinel}] run_susie_one.py failed (rc={rc})")
    else:
        pip = outdir/"susie.pip.tsv.gz"
        print(f"[verify] pip exists={pip.exists()} size={(pip.stat().st_size if pip.exists() else 0)}")

