# === Quick coloc data audit for your smoke-test window (read-only) ===
from pathlib import Path
import pandas as pd
import numpy as np

# ---- Params: set to your current test ----
SUMSTATS = "/content/drive/MyDrive/epigen_project/sumstats/GCST90000025.formatted.txt.gz"
TISSUE   = "Skeletal_Muscle"
CHR, START, END = 1, 1413861, 1913861
TOP_GENE = "ENSG00000189339.11"

# ---- Tissue EQTL paths (as in your script) ----
TISSUE_EQTL = {
    "Skeletal_Muscle": Path("/content/drive/MyDrive/epigen_project/fine_map_coloc/eqtl/gtex_v8/Skeletal_Muscle/normalized_hg19/pairs.hg19.slim.tsv.gz"),
    "Small_Intestine_Terminal_Ileum": Path("/content/drive/MyDrive/epigen_project/fine_map_coloc/eqtl/gtex_v8/Small_Intestine_Terminal_Ileum/normalized_hg19/pairs.hg19.slim.tsv.gz"),
}
EQTL_PATH = TISSUE_EQTL[TISSUE]

def pick(cols, cands):
    for c in cands:
        if c in cols: return c
    return None

print("=== GWAS sumstats header peek ===")
hdr = pd.read_csv(SUMSTATS, sep="\t", compression="infer", dtype=str, nrows=5)
print("Columns (first 5 rows read):", list(hdr.columns))

# Decide which columns to read fully
cands = {
    "chr": ["CHR","chrom","chr","#CHR","#CHROM","CHROM"],
    "bp":  ["BP","pos","POS","BP_hg19","position"],
    "p":   ["P","p","pval","p_value","PVAL","PVALUE"],
    "z":   ["Z","z","ZSTAT"],
    "b":   ["BETA","beta","Effect","effect","B"],
    "se":  ["SE","se","StdErr","stderr","SEB"],
    "af":  ["MAF","maf","AF","EAF","FRQ","A1FREQ","FREQ","af"],
    "n":   ["N","N_total","N_total_samples","Neff","NEFF","N_eff","samplesize","SAMPLESIZE"],
}
chrcol = pick(hdr.columns, cands["chr"])
bpcol  = pick(hdr.columns, cands["bp"])
usecols = set([x for x in [chrcol, bpcol] if x])

for key in ["p","z","b","se","af","n"]:
    col = pick(hdr.columns, cands[key])
    if col: usecols.add(col)

usecols = list(usecols)
if not chrcol or not bpcol:
    raise SystemExit("[GWAS] Missing CHR/BP columns; cannot proceed.")
print("Reading GWAS columns:", usecols)

SS = pd.read_csv(SUMSTATS, sep="\t", compression="infer", dtype=str, usecols=usecols)
SS[chrcol] = SS[chrcol].astype(str).str.replace("^chr","", regex=True)
SS = SS[SS[chrcol].str.fullmatch(r"\d+")]
SS[chrcol] = SS[chrcol].astype(int)
SS[bpcol]  = pd.to_numeric(SS[bpcol], errors="coerce")

# Convert numeric candidates
def numify(s): return pd.to_numeric(s, errors="coerce") if s is not None else None
pcol  = pick(SS.columns, cands["p"]);  p = numify(SS.get(pcol))
zcol  = pick(SS.columns, cands["z"]);  z = numify(SS.get(zcol))
bcol  = pick(SS.columns, cands["b"]);  b = numify(SS.get(bcol))
secol = pick(SS.columns, cands["se"]); se = numify(SS.get(secol))
afcol = pick(SS.columns, cands["af"]); af = numify(SS.get(afcol))
ncol  = pick(SS.columns, cands["n"]);  n  = numify(SS.get(ncol))

print("\n[GWAS] Present columns:")
print("  CHR:", chrcol, "BP:", bpcol,
      "| P:", pcol, "Z:", zcol, "BETA:", bcol, "SE:", secol, "AF/EAF/MAF:", afcol, "N:", ncol)

# Window slice
GW = SS[(SS[chrcol]==CHR) & (SS[bpcol]>=START) & (SS[bpcol]<=END)].copy()
print(f"[GWAS] In window chr{CHR}:{START:,}-{END:,} -> rows:", len(GW))

# Minimal p in window from whichever is available
def p_from_z(x):
    # 2*(1 - Phi(|z|)) via erfc
    from math import erfc, sqrt
    return 0.5*erfc(np.abs(x)/np.sqrt(2.0))

p_any = None
if p is not None:
    p_any = p.reindex(GW.index)
elif z is not None:
    p_any = pd.Series(p_from_z(z), index=SS.index).reindex(GW.index)
elif (b is not None) and (se is not None):
    z_any = (b / se)
    p_any = pd.Series(p_from_z(z_any), index=SS.index).reindex(GW.index)

if p_any is not None and len(GW):
    pmin = pd.to_numeric(p_any, errors="coerce").min()
    print(f"[GWAS] min p in window: {pmin}")
else:
    print("[GWAS] No P/Z/BETA+SE available to compute p in window")

# N and AF availability
if n is not None:
    n_med = np.nanmedian(n)
    print(f"[GWAS] N median (across file): {n_med}")
else:
    print("[GWAS] No N-like column detected")

if af is not None:
    maf_est = np.minimum(af, 1.0 - af)
    print(f"[GWAS] AF present; finite fraction across file: {np.isfinite(maf_est).mean():.3f}")
else:
    print("[GWAS] No AF/EAF/MAF column detected")

print("\n=== eQTL pairs header peek ===")
if not EQTL_PATH.exists():
    raise SystemExit(f"[eQTL] File not found: {EQTL_PATH}")

hdr_eq = pd.read_csv(EQTL_PATH, sep="\t", compression="infer", dtype=str, nrows=5)
print("Columns (first 5 rows read):", list(hdr_eq.columns))

eq_use = [c for c in ["CHR","BP","gene_id","pval_nominal","slope","slope_se","maf"] if c in hdr_eq.columns]
EQ = pd.read_csv(EQTL_PATH, sep="\t", compression="infer", dtype=str, usecols=eq_use)
EQ["CHR"] = EQ["CHR"].astype(str).str.replace("^chr","", regex=True)
EQ = EQ[EQ["CHR"].str.fullmatch(r"\d+")]
EQ["CHR"] = EQ["CHR"].astype(int)
EQ["BP"]  = pd.to_numeric(EQ["BP"], errors="coerce")
EQ = EQ[(EQ["CHR"]==CHR) & (EQ["BP"]>=START) & (EQ["BP"]<=END)].copy()

print(f"[eQTL] In window rows: {len(EQ)} | Columns read: {eq_use}")
if len(EQ):
    for c in ["pval_nominal","slope","slope_se","maf"]:
        if c in EQ.columns:
            cn = pd.to_numeric(EQ[c], errors="coerce")
            print(f"[eQTL] {c}: non-null frac {cn.notna().mean():.3f}, finite frac {np.isfinite(cn).mean():.3f}")
    # gene choice preview
    if "gene_id" in EQ.columns and "pval_nominal" in EQ.columns:
        gmin = EQ.groupby("gene_id")["pval_nominal"].apply(lambda s: pd.to_numeric(s, errors="coerce").min())
        g_best = gmin.idxmin()
        p_best = gmin.min()
        print(f"[eQTL] Top gene by min p in window: {g_best} (min p = {p_best})")
        if TOP_GENE:
            print(f"[eQTL] User-specified TOP_GENE exists in window?: {TOP_GENE in set(EQ['gene_id'])}")
else:
    print("[eQTL] No rows in window; check coordinates or tissue file.")

# Overlap on CHR:BP and availability of slope/slope_se on overlapped SNPs
if len(GW) and len(EQ):
    # re-create minimal GW for overlap
    GWm = GW[[chrcol, bpcol]].copy()
    GWm.columns = ["CHR","BP"]
    # dedup by CHR:BP
    if p_any is not None:
        GWm["_p"] = pd.to_numeric(p_any.reindex(GW.index), errors="coerce")
        GWm = GWm[GWm["_p"].notna()].sort_values("_p").drop_duplicates(["CHR","BP"])
        GWm.drop(columns=["_p"], inplace=True)
    else:
        GWm = GWm.drop_duplicates(["CHR","BP"])

    M = GWm.merge(EQ[["CHR","BP"] + [c for c in ["slope","slope_se","maf","gene_id","pval_nominal"] if c in EQ.columns]],
                  on=["CHR","BP"], how="inner")
    print(f"\n[OVERLAP] Shared CHR:BP rows: {len(M)}")
    if len(M):
        ok_beta = pd.to_numeric(M.get("slope"), errors="coerce").notna() & \
                  pd.to_numeric(M.get("slope_se"), errors="coerce").notna()
        print(f"[OVERLAP] Rows with slope & slope_se available: {ok_beta.sum()} / {len(M)}")
        if "maf" in M.columns:
            maf_fin = pd.to_numeric(M["maf"], errors="coerce").notna().sum()
            print(f"[OVERLAP] Rows with eQTL maf present: {maf_fin} / {len(M)}")
        print("[OVERLAP] First 5 overlapped rows preview:")
        print(M.head(5).to_string(index=False))
else:
    print("\n[OVERLAP] Not computed because one side is empty.")

