from pathlib import Path
p=Path("/content/drive/MyDrive/epigen_project/fine_map_coloc/jobs/run_coloc_one_mafsafe.py")
s=p.read_text()

anchor = 'snp_vec = (M2["CHR"].astype(str) + ":" + M2["BP"].astype(int).astype(str)).tolist()'
ins = '''
    # --- MAF hygiene for GWAS p-value mode ---
    p1_all   = pd.to_numeric(M2["p_gwas"], errors="coerce")
    afgw_all = pd.to_numeric(M2.get("AF_GW"), errors="coerce")
    maf1_all = np.minimum(afgw_all, 1.0 - afgw_all)
    if not np.isfinite(maf1_all).all():
        maf1_all = pd.to_numeric(M2.get("maf"), errors="coerce")
    maf1_all = pd.to_numeric(maf1_all, errors="coerce")
    valid = np.isfinite(p1_all) & np.isfinite(maf1_all) & (maf1_all > 0) & (maf1_all < 1)
    M3 = M2.loc[valid].copy()
    if M3.empty:
        (outdir / f"coloc_{sfx}.SKIPPED_no_valid_maf.txt").write_text("No overlapping SNPs with valid MAF (0<MAF<1) and p-values.")
        print("SKIPPED (no valid MAF)"); return
    snp_vec = (M3["CHR"].astype(str) + ":" + M3["BP"].astype(int).astype(str)).tolist()
'''

if anchor not in s:
    raise SystemExit("Anchor not found; file layout differs; aborting patch to keep original safe.")

# insert hygiene
s = s.replace(anchor, anchor + "\n" + ins)

# switch dataset builds to M3 (the cleaned overlap)
s = s.replace('beta2 = pd.to_numeric(M2["slope"], errors="coerce")', 'beta2 = pd.to_numeric(M3["slope"], errors="coerce")')
s = s.replace('varb2 = (pd.to_numeric(M2["slope_se"], errors="coerce") ** 2)', 'varb2 = (pd.to_numeric(M3["slope_se"], errors="coerce") ** 2)')
s = s.replace('maf2  = pd.to_numeric(M2["maf"], errors="coerce") if "maf" in M2.columns else None', 'maf2  = pd.to_numeric(M3["maf"], errors="coerce") if "maf" in M3.columns else None')
s = s.replace('p1   = pd.to_numeric(M2["p_gwas"], errors="coerce")', 'p1   = pd.to_numeric(M3["p_gwas"], errors="coerce")')
s = s.replace('afgw = pd.to_numeric(M2.get("AF_GW"), errors="coerce")', 'afgw = pd.to_numeric(M3.get("AF_GW"), errors="coerce")')

# clip MAF safely before build_rlist_p
s = s.replace('d1 = build_rlist_p(', 'eps=1e-12\n    maf1 = maf1.clip(lower=eps, upper=1-eps)\n    d1 = build_rlist_p(')

# tag the meta with runner_version (non-breaking)
s = s.replace('"priors": {"p1": args.p1, "p2": args.p2, "p12": args.p12},',
              '"priors": {"p1": args.p1, "p2": args.p2, "p12": args.p12},\n        "runner_version": "mafsafe-2025-08-19",')

p.write_text(s)
print("[ok] wrote mafsafe copy:", p)
PY

