import pandas as pd, os, glob
from pathlib import Path
root = Path("/content/drive/MyDrive/epigen_project")
mani = root / "fine_map_coloc" / "jobs" / "coloc_manifest.csv"
if not mani.exists():
    raise SystemExit(f"[err] manifest not found: {mani}")

df = pd.read_csv(mani)
need = {"trait","tissue","outdir"}
missing = need - set(df.columns)
if missing:
    raise SystemExit(f"[err] manifest missing columns: {sorted(missing)}")

rows = []
for (trait, tissue), g in df.groupby(["trait","tissue"]):
    total = len(g)
    done = skipped = pending = 0
    for odir in g["outdir"]:
        od = Path(odir)
        if not od.exists():
            pending += 1; continue
        has_sum  = any(Path(p).stat().st_size > 0 for p in glob.glob(str(od/"coloc_*.summary.json")))
        has_post = any(Path(p).stat().st_size > 0 for p in glob.glob(str(od/"coloc_*.snp_posteriors.tsv.gz")))
        if has_sum or has_post:
            done += 1; continue
        if glob.glob(str(od/"coloc_*.SKIPPED_*.txt")):
            skipped += 1; continue
        pending += 1
    rows.append({"trait": trait, "tissue": tissue, "total": total, "done": done, "skipped": skipped, "pending": pending})

out = pd.DataFrame(rows).sort_values(["trait","tissue"]).reset_index(drop=True)
print(out.to_string(index=False))
out.to_csv(Path("/content/drive/MyDrive/epigen_project/fine_map_coloc/jobs/coloc_status_by_trait_tissue.tsv"), sep="\t", index=False)
print("\n[wrote]", "/content/drive/MyDrive/epigen_project/fine_map_coloc/jobs/coloc_status_by_trait_tissue.tsv")
PY

