ROOT="/content/drive/MyDrive/epigen_project/deep"
SCRIPT="$ROOT/scripts/basenji_score.py"

cat > "$SCRIPT" <<'PY'
#!/usr/bin/env python3
"""
Real Basenji scorer (TensorFlow). Independent of Enformer.

Inputs
------
--cfg, --bed, --out, --variant-map, --ref-2bit, --batch-size
--bsj-model : TF SavedModel dir (has saved_model.pb) OR TF-Hub handle
--input-len: Basenji input length (default 131072; for smoke we use 1024)

Outputs
-------
Parquet:
  trait, tissue, sentinel_id, row_type, chrom, start, end, name,
  bsj_delta_max_abs_enh, bsj_delta_max_abs_prom, bsj_delta_signed_top_enh
"""
import argparse, gzip, re
from pathlib import Path
import numpy as np
import pandas as pd
from twobitreader import TwoBitFile
import pyarrow as pa
import pyarrow.parquet as pq
import tensorflow as tf
import tensorflow_hub as hub

DNA2IDX = {'A':0, 'C':1, 'G':2, 'T':3}

def parse_args():
    ap = argparse.ArgumentParser()
    ap.add_argument("--cfg", required=True)
    ap.add_argument("--bed", required=True)
    ap.add_argument("--out", required=True)
    ap.add_argument("--variant-map", default="")
    ap.add_argument("--ref-2bit", required=True)
    ap.add_argument("--batch-size", type=int, default=1)
    ap.add_argument("--bsj-model", required=True)
    ap.add_argument("--input-len", type=int, default=131072)
    return ap.parse_args()

def one_hot_np(seq: str) -> np.ndarray:
    s = seq.upper()
    L = len(s)
    arr = np.zeros((4, L), dtype=np.float32)
    for i, b in enumerate(s):
        j = DNA2IDX.get(b)
        if j is not None:
            arr[j, i] = 1.0
    return arr  # (4, L)

def get_center_from_name(name: str):
    m = re.search(r"center=(\d+)", str(name))
    return int(m.group(1)) if m else None

def load_table_auto(path: Path) -> pd.DataFrame:
    if path.suffix == ".gz":
        with gzip.open(path, "rt") as fh:
            first = fh.readline()
            sep = "\t" if "\t" in first else ","
        return pd.read_csv(path, sep=sep, compression="gzip")
    with open(path, "r") as fh:
        first = fh.readline()
        sep = "\t" if "\t" in first else ","
    return pd.read_csv(path, sep=sep)

def load_variant_map(path: str) -> dict:
    if not path:
        return {}
    p = Path(path)
    if not p.exists():
        return {}
    df = load_table_auto(p)
    need = {"name","ref_base","alt_base"}
    if not need.issubset(df.columns):
        return {}
    df = df.astype({"name":str, "ref_base":str, "alt_base":str}).groupby("name", as_index=False).last()
    return dict(zip(df["name"], zip(df["ref_base"].str.upper(), df["alt_base"].str.upper())))

def load_bed4(path: Path) -> pd.DataFrame:
    return pd.read_csv(path, sep="\t", header=None, names=["chrom","start","end","name"], engine="python")

def summarize_delta(delta: np.ndarray):
    B = delta.shape[0]
    flat = delta.reshape(B, -1)
    idx = np.argmax(np.abs(flat), axis=1)
    max_abs = np.take_along_axis(np.abs(flat), idx[:,None], axis=1)[:,0]
    signed = np.take_along_axis(flat, idx[:,None], axis=1)[:,0]
    return max_abs.astype(float), signed.astype(float)

def try_load_basenji(model_handle: str):
    p = Path(model_handle)
    if p.exists() and (p / "saved_model.pb").exists():
        m = tf.saved_model.load(model_handle)
        if hasattr(m, "signatures") and "serving_default" in m.signatures:
            infer = m.signatures["serving_default"]
            def f(x):
                try:
                    out = infer(x=x)
                except TypeError:
                    out = infer(x)
                return list(out.values())[0] if isinstance(out, dict) else out
            return f
        if callable(m):
            return m
        if hasattr(m, "predict"):
            return m.predict
        raise RuntimeError("SavedModel loaded but no obvious callable signature.")
    mod = hub.load(model_handle)
    def f(x):
        y = mod(x)
        if isinstance(y, dict):
            y = list(y.values())[0]
        if isinstance(y, (list, tuple)):
            y = y[0]
        return y
    return f

def crop_channels_last_with_left(batch_cl: np.ndarray, target_L: int, left_offsets: np.ndarray) -> np.ndarray:
    B, L, C = batch_cl.shape
    if target_L == L:
        return batch_cl
    out = np.zeros((B, target_L, C), dtype=batch_cl.dtype)
    for i in range(B):
        left = int(left_offsets[i])
        if L < target_L:
            # center-pad
            start = (target_L - L) // 2
            out[i, start:start+L, :] = batch_cl[i]
        else:
            left = max(0, min(L - target_L, left))
            right = left + target_L
            out[i] = batch_cl[i, left:right, :]
    return out

def main():
    args = parse_args()
    _ = Path(args.cfg).read_text()  # keep interface parity

    bed = load_bed4(Path(args.bed))
    tbf = TwoBitFile(args.ref_2bit)
    varmap = load_variant_map(args.variant_map) if args.variant_map else {}

    win_len = int(bed["end"].iloc[0] - bed["start"].iloc[0])
    if not (bed["end"] - bed["start"]).eq(win_len).all():
        raise SystemExit("[ERR] Not all windows share the same length.")
    if args.input_len <= 0 or args.input_len > win_len:
        raise SystemExit(f"[ERR] --input-len must be 1..{win_len}")

    bsj_fn = try_load_basenji(args.bsj_model)
    print("[preflight] Basenji model loaded ✓")

    Bsize = max(1, int(args.batch_size))
    out_rows = []

    for i in range(0, len(bed), Bsize):
        chunk = bed.iloc[i:i+Bsize].reset_index(drop=True)

        ref_arrays, alt_arrays, left_offsets, meta = [], [], [], []
        for _, r in chunk.iterrows():
            chrom = str(r["chrom"]); start = int(r["start"]); end = int(r["end"]); name = str(r["name"])
            center_bp = get_center_from_name(name)

            seq_ref = tbf[chrom][start:end]
            if len(seq_ref) != win_len:
                seq_ref = (seq_ref + "N" * win_len)[:win_len]
            ref_arrays.append(one_hot_np(seq_ref))  # (4,L)

            # ALT mutation logic (compute off deterministically)
            off = -1
            ref_b = alt_b = None
            if center_bp is not None and name in varmap:
                ref_b, alt_b = varmap[name]
                off = center_bp - start
            if 0 <= off < win_len and ref_b in DNA2IDX and alt_b in DNA2IDX:
                s = list(seq_ref.upper())
                s[off] = alt_b
                alt_arrays.append(one_hot_np("".join(s)))
            else:
                alt_arrays.append(ref_arrays[-1])

            # left offset to center the crop on the variant (or middle if unknown)
            if center_bp is not None:
                left = (center_bp - start) - (args.input_len // 2)
                left = max(0, min(win_len - args.input_len, left))
            else:
                left = (win_len - args.input_len) // 2
            left_offsets.append(left)
            meta.append((chrom, start, end, name))

        ref_cl = np.transpose(np.stack(ref_arrays, axis=0), (0,2,1)).astype(np.float32)  # (B,L,4)
        alt_cl = np.transpose(np.stack(alt_arrays, axis=0), (0,2,1)).astype(np.float32)  # (B,L,4)
        ref_crops = crop_channels_last_with_left(ref_cl, args.input_len, np.array(left_offsets))
        alt_crops = crop_channels_last_with_left(alt_cl, args.input_len, np.array(left_offsets))
        print(f"[debug] BSJ ref/alt crops:", ref_crops.shape)

        x_ref = tf.convert_to_tensor(ref_crops, dtype=tf.float32)
        x_alt = tf.convert_to_tensor(alt_crops, dtype=tf.float32)
        ref_pred = bsj_fn(x_ref)
        alt_pred = bsj_fn(x_alt)

        def to_np(y):
            if isinstance(y, dict): y = list(y.values())[0]
            if isinstance(y, (list, tuple)): y = y[0]
            return y.numpy() if hasattr(y, "numpy") else np.array(y)
        ref_np = to_np(ref_pred); alt_np = to_np(alt_pred)
        if ref_np.ndim < 2:
            ref_np = ref_np.reshape(ref_np.shape[0], -1)
            alt_np = alt_np.reshape(alt_np.shape[0], -1)

        delta = alt_np - ref_np
        max_abs, signed_top = summarize_delta(delta)

        for j, (chrom, start, end, name) in enumerate(meta):
            parts = name.split("|")
            trait  = parts[0] if len(parts) > 0 else None
            tissue = parts[1] if len(parts) > 1 else None
            sentinel = parts[2] if len(parts) > 2 else None
            row_type = "credset_variant" if "credset_variant" in name else ("lead_window_2kb" if "lead_window_2kb" in name else "unknown")
            out_rows.append({
                "trait": trait, "tissue": tissue, "sentinel_id": sentinel,
                "row_type": row_type, "chrom": chrom, "start": int(start), "end": int(end), "name": name,
                "bsj_delta_max_abs_enh": float(max_abs[j]),
                "bsj_delta_max_abs_prom": float(max_abs[j]),
                "bsj_delta_signed_top_enh": float(signed_top[j]),
            })

    out_df = pd.DataFrame(out_rows, columns=[
        "trait","tissue","sentinel_id","row_type","chrom","start","end","name",
        "bsj_delta_max_abs_enh","bsj_delta_max_abs_prom","bsj_delta_signed_top_enh"
    ])
    out_path = Path(args.out).expanduser().resolve()
    out_path.parent.mkdir(parents=True, exist_ok=True)
    pq.write_table(pa.Table.from_pandas(out_df, preserve_index=False), out_path)
    print(f"[basenji_score] wrote {out_path} rows={len(out_df)}")

if __name__ == "__main__":
    main()
PY

