import os, json, numpy as np, pandas as pd, pyarrow.parquet as pq

root="/content/drive/MyDrive/epigen_project/deep"
p=f"{root}/scoring/enf_bsj_variant_scores.hg38.all.parquet"
assert os.path.exists(p), f"[ERR] not found: {p}"

df = pq.read_table(p).to_pandas()

# Columns sanity
needed = ["chrom","start","end","name",
          "enf_delta_max_abs_enh","enf_delta_signed_top_enh",
          "bsj_delta_signed_top_enh","agree_enf_bsj_enh","functional_support_v1"]
missing = [c for c in needed if c not in df.columns]
assert not missing, f"[ERR] missing columns: {missing}"

# Recompute p90 for record; basic tallies
p90 = float(df["enf_delta_max_abs_enh"].quantile(0.90))
tot = len(df)
n_sup = int(df["functional_support_v1"].sum())
n_dis = int((df["agree_enf_bsj_enh"]==0.0).sum())

# Dup checks
keys = ["chrom","start","end","name"]
dup_cnt = int(df.duplicated(subset=keys, keep=False).sum())

# Per-trait/tissue summaries
by_trait = (df.groupby("trait", dropna=False)
              .agg(total=("name","size"),
                   supported=("functional_support_v1","sum"))
              .reset_index())
by_trait["supported_pct"] = (by_trait["supported"]/by_trait["total"]*100).round(2)

by_tissue = (df.groupby("tissue", dropna=False)
               .agg(total=("name","size"),
                    supported=("functional_support_v1","sum"))
               .reset_index())
by_tissue["supported_pct"] = (by_tissue["supported"]/by_tissue["total"]*100).round(2)

# Top effects & disagreements (limited for convenience)
top_effects = (df.sort_values("enf_delta_max_abs_enh", ascending=False)
                 .loc[:, ["trait","tissue","chrom","start","end","name",
                          "enf_delta_max_abs_enh","enf_delta_signed_top_enh",
                          "bsj_delta_signed_top_enh","agree_enf_bsj_enh","functional_support_v1"]]
                 .head(50))

disagreements = df.loc[df["agree_enf_bsj_enh"]==0.0,
                       ["trait","tissue","chrom","start","end","name",
                        "enf_delta_signed_top_enh","bsj_delta_signed_top_enh",
                        "enf_delta_max_abs_enh"]].copy()

# Persist report artifacts
report_dir=f"{root}/scoring/reports"
os.makedirs(report_dir, exist_ok=True)

with open(f"{report_dir}/summary.overall.json","w") as fh:
    json.dump({
        "rows": tot,
        "p90_enf_abs": p90,
        "supported_count": n_sup,
        "supported_pct": round(100*n_sup/max(tot,1),2),
        "sign_disagree_count": n_dis,
        "duplicates_by_key": dup_cnt
    }, fh, indent=2)

by_trait.to_csv(f"{report_dir}/summary.by_trait.tsv.gz", sep="\t", index=False, compression="gzip")
by_tissue.to_csv(f"{report_dir}/summary.by_tissue.tsv.gz", sep="\t", index=False, compression="gzip")
top_effects.to_csv(f"{report_dir}/top_effects.enf.tsv.gz", sep="\t", index=False, compression="gzip")
disagreements.to_csv(f"{report_dir}/disagreements.tsv.gz", sep="\t", index=False, compression="gzip")

# On-screen preview
print("[13.8C] overall:", json.dumps({
    "rows": tot, "p90_enf_abs": round(p90,6),
    "supported": n_sup, "sign_disagree": n_dis,
    "duplicates_by_key": dup_cnt
}, indent=2))
print("\n[by_trait head]")
print(by_trait.head(10).to_string(index=False))
print("\n[top_effects head]")
