import os, re, gzip
import pandas as pd

proj = "/content/drive/MyDrive/epigen_project"
canon  = f"{proj}/external/regulatory_overlaps.tsv.gz"
detail = f"{proj}/external/regulatory_overlaps.with_h3k27ac_perEID.tsv.gz"
