import pandas as pd, numpy as np, pyarrow as pa, pyarrow.parquet as pq

proj="/content/drive/MyDrive/epigen_project"; ens=f"{proj}/ensemble"; ext=f"{proj}/external"
feat=f"{ens}/features/feature_matrix.v1.parquet"
ovlp=f"{ext}/regulatory_overlaps.tsv.gz"

df=pq.read_table(feat).to_pandas()
reg=pd.read_csv(ovlp, sep="\t")

# drop any stale ovl_* cols then merge new ones
df=df.drop(columns=[c for c in df.columns if c.startswith("ovl_")], errors="ignore") \
     .merge(reg, on="name", how="left", validate="m:1")

# label rule: (max(PP4) ≥ 0.8) AND any regulatory overlap == 1
pp4_max=pd.concat([df.get("pp4_eqtl"), df.get("pp4_mqtl")], axis=1).max(axis=1, skipna=True)
ovl_cols=["ovl_E084","ovl_E085","ovl_E090","ovl_E091","ovl_h3k27ac_muscle"]
df["positive_label"]=((pp4_max>=0.8) & (df[ovl_cols].fillna(0).astype(float).max(axis=1)>=1)).astype("int8")

pq.write_table(pa.Table.from_pandas(df, preserve_index=False), feat)
df.to_csv(f"{ens}/features/feature_matrix.v1.tsv.gz", sep="\t", index=False, compression="gzip")

print(f"[14.1S] rows={len(df)} | positives={int(df['positive_label'].sum())} | H3K27ac_hits={(df['ovl_h3k27ac_muscle']>0).sum()}")
print("[14.1S] preview:")
