import os, pandas as pd, numpy as np, pyarrow as pa, pyarrow.parquet as pq

PROJ="/content/drive/MyDrive/epigen_project"
SCOR=f"{PROJ}/deep/scoring"
CONF=f"{SCOR}/confidence"
ENS=f"{PROJ}/ensemble"
EXT=f"{PROJ}/external"

MERGED=f"{SCOR}/enf_bsj_variant_scores.hg38.all.parquet"
SUP_ALL=f"{CONF}/supported.all.parquet"
SUP_SLIM=f"{CONF}/enf_bsj_confidence.slim.parquet"
OVLP=f"{EXT}/regulatory_overlaps.all.tsv.gz"

OUT_PARQ=f"{ENS}/features/model_matrix.v2.parquet"
OUT_TSV=f"{ENS}/features/model_matrix.v2.tsv.gz"

assert os.path.exists(MERGED), f"[ERR] missing merged scores: {MERGED}"
assert os.path.exists(OVLP),   f"[ERR] missing overlaps: {OVLP}"

m = pd.read_parquet(MERGED)

# --- overlaps: collapse to 1 row per name ---
ov = pd.read_csv(OVLP, sep="\t")
ov_cols = [c for c in ov.columns if c.startswith("ovl_")]
ov = ov.groupby("name", as_index=False)[ov_cols].max()

# --- supported membership (label source) ---
supported_names = set()
if os.path.exists(SUP_ALL):
    s = pd.read_parquet(SUP_ALL)
    if "name" in s.columns:
        supported_names.update(s["name"].astype(str).tolist())
if os.path.exists(SUP_SLIM):
    s2 = pd.read_parquet(SUP_SLIM)
    if "name" in s2.columns:
        # if the slim has functional_support_v1, filter to ==1; else just take all names
        if "functional_support_v1" in s2.columns:
            s2 = s2[s2["functional_support_v1"] == 1]
        supported_names.update(s2["name"].astype(str).tolist())

assert len(supported_names) > 0, "[ERR] No supported names found; check confidence folder paths"

# --- assemble feature matrix ---
df = (m
      .merge(ov, on="name", how="left", validate="m:1")
      .copy())

# locus id
df = df.rename(columns={"sentinel_id":"locus_id"})

# positive_label by membership
df["positive_label"] = df["name"].astype(str).isin(supported_names).astype("int8")

# keep core features
keep = ["locus_id","trait","tissue","chrom","start","end","name",
        "enf_delta_max_abs_enh","enf_delta_signed_top_enh",
        "bsj_delta_max_abs_enh","bsj_delta_signed_top_enh"] + ov_cols + ["positive_label"]
df = df[keep]

# write
pq.write_table(pa.Table.from_pandas(df, preserve_index=False), OUT_PARQ)
df.to_csv(OUT_TSV, sep="\t", index=False, compression="gzip")

n = len(df); pos = int(df["positive_label"].sum())
print(f"[14.2B.fix] rows={n} | positives={pos} | negatives={n-pos}")
print("[14.2B.fix] preview:")
print(df.head(6).to_string(index=False))
print(f"[14.2B.fix] wrote -> {OUT_PARQ}")
print(f"[14.2B.fix] wrote -> {OUT_TSV}")
PY

