import json, numpy as np, pandas as pd
from pathlib import Path
from sklearn.impute import SimpleImputer
from sklearn.preprocessing import StandardScaler
from sklearn.pipeline import Pipeline
from sklearn.isotonic import IsotonicRegression
from sklearn.metrics import roc_auc_score, average_precision_score, brier_score_loss
from sklearn.model_selection import StratifiedShuffleSplit
from lightgbm import LGBMClassifier

PROJ="/content/drive/MyDrive/epigen_project"
ENS=f"{PROJ}/ensemble"
MAT=f"{ENS}/features/model_matrix.v2.folds_logo.parquet"
OUT=f"{ENS}/models/lgbm_logo"
Path(OUT).mkdir(parents=True, exist_ok=True)

df = pd.read_parquet(MAT)
assert "positive_label" in df.columns
assert "fold_outer_logo" in df.columns

# Same core feature family as before; intersect with columns
cand_feats = [
    "enf_delta_max_abs_enh","enf_delta_signed_top_enh",
    "bsj_delta_max_abs_enh","bsj_delta_signed_top_enh",
    "ovl_E084","ovl_E085","ovl_E090","ovl_E091","ovl_h3k27ac_muscle",
    "pp4_eqtl","pp4_mqtl","susie_pip","ldsc_ann_score",
    "dist_myogenesis_genes_kb","dist_epithelium_genes_kb","cpg_neighborhood"
]
feats = [c for c in cand_feats if c in df.columns]

# Tree model wrapped with simple impute/scale (scale doesn’t hurt but isn’t required)
pipe = Pipeline([
    ("imp", SimpleImputer(strategy="median")),
    ("sc",  StandardScaler(with_mean=False)),  # keep sparse-friendly behavior
    ("clf", LGBMClassifier(
        n_estimators=500,
        learning_rate=0.05,
        max_depth=3,
        num_leaves=15,
        subsample=0.8,
        colsample_bytree=0.8,
        min_child_samples=20,
        objective="binary",
        class_weight="balanced",
        random_state=42,
        n_jobs=-1
    ))
])

folds = sorted(df["fold_outer_logo"].dropna().unique().tolist())
pred_rows, fold_metrics = [], []
n_cal_ok = n_cal_skip = 0

for k in folds:
    te = df["fold_outer_logo"] == k
    tr = ~te

    X_tr = df.loc[tr, feats].values
    y_tr = df.loc[tr, "positive_label"].astype(int).values
    X_te = df.loc[te, feats].values
    y_te = df.loc[te, "positive_label"].astype(int).values

    can_cal = (len(np.unique(y_tr)) == 2) and (len(y_tr) >= 10) and (y_tr.sum() >= 2) and ((len(y_tr)-y_tr.sum()) >= 2)
    if can_cal:
        sss = StratifiedShuffleSplit(n_splits=1, test_size=0.2, random_state=42)
        fit_idx, cal_idx = next(sss.split(X_tr, y_tr))
        X_fit, y_fit = X_tr[fit_idx], y_tr[fit_idx]
        X_cal, y_cal = X_tr[cal_idx], y_tr[cal_idx]

        pipe.fit(X_fit, y_fit)
        p_cal = pipe.predict_proba(X_cal)[:,1]

        if len(np.unique(y_cal)) == 2 and len(np.unique(p_cal)) > 1:
            iso = IsotonicRegression(out_of_bounds="clip")
            iso.fit(p_cal, y_cal)
            p_te = iso.predict(pipe.predict_proba(X_te)[:,1])
            cal_used = True
            n_cal_ok += 1
        else:
            pipe.fit(X_tr, y_tr)
            p_te = pipe.predict_proba(X_te)[:,1]
            cal_used = False
            n_cal_skip += 1
    else:
        pipe.fit(X_tr, y_tr)
        p_te = pipe.predict_proba(X_te)[:,1]
        cal_used = False
        n_cal_skip += 1

    sub = df.loc[te, ["locus_id","name"]].copy()
    sub["fold"] = k
    sub["y_true"] = y_te
    sub["y_pred_calibrated"] = p_te
    sub["calibrated"] = int(cal_used)
    pred_rows.append(sub)

    # Metrics per fold
    try: auc = roc_auc_score(y_te, p_te)
    except ValueError: auc = None
    try: ap  = average_precision_score(y_te, p_te)
    except ValueError: ap = None
    bs = brier_score_loss(y_te, p_te) if len(y_te) else None

    fold_metrics.append({
        "fold": int(k),
        "rows": int(len(y_te)),
        "positives": int(y_te.sum()),
        "negatives": int((1-y_te).sum()),
        "auroc": (None if auc is None else float(auc)),
        "average_precision": (None if ap is None else float(ap)),
        "brier": (None if bs is None else float(bs)),
        "calibrated": bool(cal_used)
    })

pred = pd.concat(pred_rows, ignore_index=True)
pred_parq = f"{OUT}/predictions.calibrated.parquet"
pred_tsv  = f"{OUT}/predictions.calibrated.tsv.gz"
pred.to_parquet(pred_parq, index=False)
pred.to_csv(pred_tsv, sep="\t", index=False, compression="gzip")

ok = [m for m in fold_metrics if (m["auroc"] is not None and m["average_precision"] is not None)]
overall = {
    "auroc_mean": (None if not ok else float(np.mean([m["auroc"] for m in ok]))),
    "ap_mean":    (None if not ok else float(np.mean([m["average_precision"] for m in ok]))),
    "brier_mean": (None if not ok else float(np.mean([m["brier"] for m in ok]))),
    "eval_folds": len(ok)
}
report = {
    "n_rows": int(len(df)),
    "n_feats_used": len(feats),
    "features": feats,
    "n_folds": len(folds),
    "calibration": {"folds_calibrated": n_cal_ok, "folds_skipped": n_cal_skip, "method": "isotonic (train-only split 80/20)"},
    "fold_metrics": fold_metrics,
    "overall": overall,
    "model": {"type": "lightgbm", "params": pipe.named_steps["clf"].get_params()}
}
with open(f"{OUT}/metrics.calibrated.json","w") as fh:
    json.dump(report, fh, indent=2)

print("[14.2G] wrote →", pred_parq)
print("[14.2G] wrote →", pred_tsv)
print("[14.2G] metrics:")
print(json.dumps(report, indent=2))
PY

