ttf_pq = f"{GRN}/edges.expr_supported.top_by_myogenic_tf.k50.parquet"
ttf_tsv= f"{GRN}/edges.expr_supported.top_by_myogenic_tf.k50.tsv.gz"
top_global.to_parquet(tg_pq, index=False)
top_global.to_csv(tg_tsv, sep="\t", index=False, compression="gzip")
top_by_tf.to_parquet(ttf_pq, index=False)
top_by_tf.to_csv(ttf_tsv, sep="\t", index=False, compression="gzip")

summary = {
  "expr_threshold": THR,
  "edges_after_expr_filter": int(E2.shape[0]),
  "top_global_rows": int(top_global.shape[0]),
  "myogenic_tfs_present": sorted(top_by_tf["tf_symbol"].unique().tolist()),
  "top_by_myogenic_tf_rows": int(top_by_tf.shape[0]),
  "outputs": {"top_global": [tg_pq, tg_tsv], "top_by_myogenic_tf": [ttf_pq, ttf_tsv]}
}
print("[15.7C.fix] summary:", json.dumps(summary, indent=2))
print("[15.7C.fix] head:")
print(E2.head(10).to_string(index=False))
